# # # # # # # # # # # #                                 device=fm_vel_pred.device,
# # # # # # # # # # # #                                 dtype=fm_vel_pred.dtype)
# # # # # # # # # # # #             reg = fm_vel_pred.new_zeros(())
# # # # # # # # # # # #         else:
