# # # # # # # # # # # #         L_logspd = l_logspeed(pred_deg[:T], gt_deg[:T])
# # # # # # # # # # # #         L_curv   = l_curvature(pred_deg[:T])

# # # # # # # # # # # #         total = (1.0    * L_fm
# # # # # # # # # # # #                + lam[0] * L_kin
# # # # # # # # # # # #                + lam[1] * L_logspd
# # # # # # # # # # # #                + lam[2] * L_curv
# # # # # # # # # # # #                + reg)

# # # # # # # # # # # #         if not torch.isfinite(total):
