# # # # # # # # # # # #             "l_curv":      L_curv.item(),
# # # # # # # # # # # #             "l_reg":       reg.item() if torch.is_tensor(reg) else 0.0,
# # # # # # # # # # # #             "diff_w_mean": sample_w.mean().item(),
# # # # # # # # # # # #             "lam_kin":     lam[0].item(),
# # # # # # # # # # # #             "lam_logspd":  lam[1].item(),
# # # # # # # # # # # #             "lam_curv":    lam[2].item(),
# # # # # # # # # # # #             **sw_d,
# # # # # # # # # # # #         }
