# # # # # # # # # # # #     def forward(
# # # # # # # # # # # #         self,
# # # # # # # # # # # #         pred_deg:      torch.Tensor,
# # # # # # # # # # # #         gt_deg:        torch.Tensor,
# # # # # # # # # # # #         fm_vel_pred:   torch.Tensor,
# # # # # # # # # # # #         fm_vel_target: torch.Tensor,
# # # # # # # # # # # #         candidates:    Optional[list] = None,
# # # # # # # # # # # #         obs_norm:      Optional[torch.Tensor] = None,
