# # # # # # # # # # #     L_fm:   velocity MSE (flow matching)
# # # # # # # # # # #     L_pos:  haversine position loss (ADE proxy, DIRECT)
# # # # # # # # # # #     L_disp: normalized displacement (ATE+CTE proxy, INDIRECT)
# # # # # # # # # # #     """
# # # # # # # # # # #     def __init__(self, pred_len=12):
