# # # # # # # # # #     """
# # # # # # # # # #     K=3 mode clustering tại 72h endpoint.
# # # # # # # # # #     Thay top-35% median → CTE thấp hơn tự nhiên.

# # # # # # # # # #     trajs_norm: list of [T,B,2] seq-first normalized
# # # # # # # # # #     obs_norm:   [T_obs,B,2] seq-first
# # # # # # # # # #     scorer:     EnsembleScorer
