# # # # # # # # # #     @staticmethod
# # # # # # # # # #     def _lon_flip_aug(bl, p=0.35):
# # # # # # # # # #         """
# # # # # # # # # #         Flip longitude: lon_norm → -lon_norm.
# # # # # # # # # #         Mô phỏng bão ở phía đối xứng → model học invariant với hướng E/W.
# # # # # # # # # #         Giảm val-test gap vì test set có nhiều bão hướng khác nhau hơn.
