# # # # # # # # #     def logits(
# # # # # # # # #         self,
# # # # # # # # #         traj_norm: torch.Tensor,
# # # # # # # # #         obs_norm:  torch.Tensor,
# # # # # # # # #     ) -> torch.Tensor:
# # # # # # # # #         """Returns [B] raw logits (for BCE_with_logits, AMP-safe)."""
