# # # # # # # # # TCDiffusion = TCFlowMatching

# # # # # # # # """
# # # # # # # # flow_matching_model.py  TC-FlowMatching v75
# # # # # # # # ============================================================
# # # # # # # # TARGET: ADE<172.68 | 72h<321.39 | ATE<142.21 | CTE<42.04

# # # # # # # # ROOT CAUSES từ v74 log (ep0-30, best score=120.16 tại ep27):
# # # # # # # #   P1: ConstrainedLossWeights tự học theo val_loss tổng, KHÔNG theo ADE signal
# # # # # # # #       → weights học đúng minimize loss nhưng không minimize ADE
# # # # # # # #   P2: step_weights ratio giảm từ 12→6 (theo log) → model bỏ focus 72h
# # # # # # # #   P3: EMA tốt hơn raw 5-10đ nhưng inference dùng raw weights (lãng phí)
# # # # # # # #   P4: val_loss dùng augmented data → noisy signal cho scheduler

# # # # # # # # FIXES v75:
# # # # # # # #   F1: ADEGuidedLossWeights — 5 weights tự học, init w_pos_l=3x > w_pos_e=1.5x
# # # # # # # #       → w_pos_l/w_pos_e ratio phải >1.5 mọi lúc (gradient trực tiếp từ 72h)
# # # # # # # #   F2: SeparateStepWeights — 2 bộ riêng, init linspace(-0.3,1.3) → ratio=21x ngay từ đầu
# # # # # # # #       → không thể giảm về 2x như v74 vì init cao và penalty ratio>=5x
# # # # # # # #   F3: sample() mặc định use_ema_for_inference=True
# # # # # # # #   F4: l_position_split: early(step0-5, delta=200km) và late(step6-11, delta=400km)
# # # # # # # #       → L_pos_late dominant → gradient mạnh tại 72h
# # # # # # # #   F5: l_displacement_normalized: ratio clamp(max=5) + /2.0 → scale đúng
# # # # # # # #   F6: l_endpoint_72h: explicit 72h/48h endpoint loss (delta=250km)

# # # # # # # # LOSS:
# # # # # # # #   total = w_fm*L_fm + w_pos_e*L_pos_e + w_pos_l*L_pos_l
# # # # # # # #         + w_disp*L_disp_norm + w_ep*L_ep_72h
# # # # # # # #         + 0.15*L_speed_aux + 0.03*L_scorer_aux
# # # # # # # #         + anchor_loss + step_penalty
# # # # # # # #   (tất cả w_* tự học)
# # # # # # # # """
