# # # # # # # # def l_position_split(pred_deg: torch.Tensor,   # [T,B,2]
# # # # # # # #                      gt_deg:   torch.Tensor,   # [T,B,2]
# # # # # # # #                      sw_pos:   torch.Tensor,   # [12]
# # # # # # # #                      sample_w: torch.Tensor    # [B]
# # # # # # # #                      ) -> Tuple[torch.Tensor, torch.Tensor]:
# # # # # # # #     """
# # # # # # # #     L_pos tách early(step0-5) và late(step6-11).

# # # # # # # #     Early: huber delta=200km → penalize >200km error, scale /200
# # # # # # # #     Late:  huber delta=400km → allow more, but still penalize, scale /400
# # # # # # # #     Cả hai weight bởi sw_pos (late steps có sw_pos cao hơn nhiều vì ratio=21x)
# # # # # # # #     và sample_w (hard storms weight cao hơn).

# # # # # # # #     Tại sao tách thay vì dùng chung?
# # # # # # # #     - Dùng chung: w_pos_l học theo average của cả 12 steps
# # # # # # # #     - Tách: w_pos_l học RIÊNG cho late steps → gradient 100% từ 72h signal
# # # # # # # #     - L_pos_l/L_pos_e ratio học tự nhiên phản ánh khó dự báo 72h vs 6h
# # # # # # # #     """
# # # # # # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # # # # # #     if T < 2:
# # # # # # # #         return pred_deg.new_zeros(()), pred_deg.new_zeros(())

# # # # # # # #     dist = haversine_km(pred_deg[:T], gt_deg[:T])   # [T,B]
# # # # # # # #     sw = sw_pos[:T]                                  # [T]

# # # # # # # #     # Early: step 0-5 (6h-36h), delta=200km
# # # # # # # #     early_end = min(6, T)
# # # # # # # #     d_e  = dist[:early_end]; sw_e = sw[:early_end]  # [early_end,B], [early_end]
# # # # # # # #     h_e  = torch.where(d_e < 200., d_e.pow(2)/400., d_e - 100.)
# # # # # # # #     l_e  = (h_e * sw_e.unsqueeze(1) * sample_w.unsqueeze(0)).mean() / 200.

# # # # # # # #     # Late: step 6-11 (42h-72h), delta=400km
# # # # # # # #     if T <= 6:
# # # # # # # #         return l_e, pred_deg.new_zeros(())
# # # # # # # #     d_l  = dist[6:T]; sw_l = sw[6:T]                # [T-6,B], [T-6]
# # # # # # # #     h_l  = torch.where(d_l < 400., d_l.pow(2)/800., d_l - 200.)
# # # # # # # #     l_l  = (h_l * sw_l.unsqueeze(1) * sample_w.unsqueeze(0)).mean() / 400.

# # # # # # # #     return l_e, l_l


# # # # # # # # def l_displacement_normalized(pred_deg: torch.Tensor,   # [T,B,2]
# # # # # # # #                                gt_deg:   torch.Tensor,   # [T,B,2]
# # # # # # # #                                sw_disp:  torch.Tensor,   # [11]
# # # # # # # #                                sample_w: torch.Tensor    # [B]
# # # # # # # #                                ) -> torch.Tensor:
# # # # # # # #     """
# # # # # # # #     ||Δpred - Δgt||_km / max(||Δgt||_km, 10km)

# # # # # # # #     ATE proxy: khi speed sai (||Δpred|| ≠ ||Δgt||)
# # # # # # # #     CTE proxy: khi direction sai (direction(Δpred) ≠ direction(Δgt))

# # # # # # # #     CRITICAL: ratio.clamp(max=5.) để tránh outlier storms gây loss explosion.
# # # # # # # #     /2.0: normalize scale → [0, ~1.5], comparable với l_pos_late.
# # # # # # # #     """
# # # # # # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # # # # # #     if T < 3:
# # # # # # # #         return pred_deg.new_zeros(())

# # # # # # # #     # cos_lat dùng gt latitude tại mid-point (T-1 displacements)
# # # # # # # #     cos_lat = torch.cos(torch.deg2rad(gt_deg[1:T, :, 1])).clamp(1e-4)  # [T-1,B]

# # # # # # # #     def _disp_km(traj):
# # # # # # # #         dx = (traj[1:T,:,0] - traj[:T-1,:,0]) * cos_lat * DEG2KM
# # # # # # # #         dy = (traj[1:T,:,1] - traj[:T-1,:,1]) * DEG2KM
# # # # # # # #         return torch.stack([dx, dy], dim=-1)  # [T-1,B,2]

# # # # # # # #     dp = _disp_km(pred_deg)
# # # # # # # #     dg = _disp_km(gt_deg)

# # # # # # # #     err_km = (dp - dg).norm(dim=-1)               # [T-1,B]
# # # # # # # #     gt_mag = dg.norm(dim=-1).clamp(min=10.)        # [T-1,B]
# # # # # # # #     ratio  = (err_km / gt_mag).clamp(max=5.)       # [T-1,B] ∈ [0,5]

# # # # # # # #     huber = F.huber_loss(ratio, torch.zeros_like(ratio),
# # # # # # # #                           delta=1.0, reduction='none')  # [T-1,B]
# # # # # # # #     n_disp = T - 1
# # # # # # # #     sw = sw_disp[:n_disp]
# # # # # # # #     return (huber * sw.unsqueeze(1) * sample_w.unsqueeze(0)).mean() / 2.0


# # # # # # # # def l_endpoint_72h(pred_deg: torch.Tensor,   # [T,B,2]
# # # # # # # #                    gt_deg:   torch.Tensor,   # [T,B,2]
# # # # # # # #                    sample_w: torch.Tensor    # [B]
# # # # # # # #                    ) -> torch.Tensor:
# # # # # # # #     """
# # # # # # # #     Explicit endpoint emphasis: 48h (step7, weight=0.4) + 72h (step11, weight=1.0).
# # # # # # # #     delta=250km (tighter than l_pos_late's 400km).
# # # # # # # #     Gradient trực tiếp đến 72h step, riêng biệt với l_pos_late.
# # # # # # # #     Scale: /250 → [0, ~2].
# # # # # # # #     """
# # # # # # # #     T = pred_deg.shape[0]
# # # # # # # #     total = pred_deg.new_zeros(())
# # # # # # # #     w_sum = 0.
# # # # # # # #     for s, w in [(7, 0.4), (11, 1.0)]:
# # # # # # # #         if s < T:
# # # # # # # #             d = haversine_km(pred_deg[s], gt_deg[s])   # [B]
# # # # # # # #             h = torch.where(d < 250., d.pow(2) / 500., d - 125.)
# # # # # # # #             total = total + w * (h * sample_w).mean() / 250.
# # # # # # # #             w_sum += w
# # # # # # # #     return total / max(w_sum, 1e-6)


# # # # # # # # def l_speed_aux(speed_pred: torch.Tensor,   # [B,T]
# # # # # # # #                 pred_deg:   torch.Tensor,   # [T,B,2]
# # # # # # # #                 gt_deg:     torch.Tensor,   # [T,B,2]
# # # # # # # #                 sw_pos:     torch.Tensor    # [12]
# # # # # # # #                 ) -> torch.Tensor:
# # # # # # # #     """Log-space speed MSE, weight 0.15 (fixed small)."""
# # # # # # # #     T = min(speed_pred.shape[1] + 1, gt_deg.shape[0])
# # # # # # # #     if T < 2: return speed_pred.new_zeros(())
# # # # # # # #     v_gt   = velocity_km_s(gt_deg[:T])              # [T-1,B,2]
# # # # # # # #     spd_gt = v_gt.norm(dim=-1).clamp(3.).permute(1,0)  # [B,T-1]
# # # # # # # #     n  = min(speed_pred.shape[1], spd_gt.shape[1])
# # # # # # # #     sw = sw_pos[:n]; sw = sw / sw.sum()
# # # # # # # #     mse = F.mse_loss(torch.log1p(speed_pred[:,:n]),
# # # # # # # #                      torch.log1p(spd_gt[:,:n]), reduction='none')
# # # # # # # #     return (mse * sw.unsqueeze(0)).mean()


