# # # # # # # # class FMv75Loss(nn.Module):
# # # # # # # #     """
# # # # # # # #     v75 Master Loss.
# # # # # # # #     Total = w_fm*L_fm + w_pos_e*L_pos_e + w_pos_l*L_pos_l
# # # # # # # #           + w_disp*L_disp + w_ep*L_ep
# # # # # # # #           + 0.15*L_speed + 0.03*L_scorer
# # # # # # # #           + anchor_loss + step_penalty
# # # # # # # #     """
# # # # # # # #     def __init__(self, pred_len: int = 12):
# # # # # # # #         super().__init__()
# # # # # # # #         self.pred_len     = pred_len
