# # # # # # # #         self.loss_weights = ADEGuidedLossWeights(
# # # # # # # #             init_fm=1.0, init_pos_e=1.5, init_pos_l=3.0,
# # # # # # # #             init_disp=1.0, init_ep=1.0, anchor_w=0.01)
# # # # # # # #         self.diff_weighter = DifficultyWeighter()
# # # # # # # #         self.scorer        = EnsembleScorer()

# # # # # # # #     def forward(self,
# # # # # # # #                 pred_deg:      torch.Tensor,   # [T,B,2]
# # # # # # # #                 gt_deg:        torch.Tensor,   # [T,B,2]
# # # # # # # #                 fm_vel_pred:   torch.Tensor,   # [B,T,4]
# # # # # # # #                 fm_vel_target: torch.Tensor,   # [B,T,4]
# # # # # # # #                 speed_pred:    Optional[torch.Tensor] = None,
# # # # # # # #                 candidates:    Optional[list] = None,
# # # # # # # #                 obs_norm:      Optional[torch.Tensor] = None,
# # # # # # # #                 epoch:         int = 0
# # # # # # # #                 ) -> Tuple[torch.Tensor, dict]:

# # # # # # # #         T = min(pred_deg.shape[0], gt_deg.shape[0])

# # # # # # # #         sample_w = self.diff_weighter(gt_deg[:T])   # [B] ∈[1,2]
# # # # # # # #         sw_pos   = self.step_weights.pos_weights()  # [12]
# # # # # # # #         sw_disp  = self.step_weights.disp_weights() # [11]

# # # # # # # #         w_fm    = self.loss_weights.w_fm()
# # # # # # # #         w_pos_e = self.loss_weights.w_pos_e()
# # # # # # # #         w_pos_l = self.loss_weights.w_pos_l()
# # # # # # # #         w_disp  = self.loss_weights.w_disp()
# # # # # # # #         w_ep    = self.loss_weights.w_ep()

# # # # # # # #         L_fm              = l_fm_loss(fm_vel_pred, fm_vel_target)
# # # # # # # #         L_pos_e, L_pos_l  = l_position_split(pred_deg[:T], gt_deg[:T], sw_pos, sample_w)
# # # # # # # #         L_disp            = l_displacement_normalized(pred_deg[:T], gt_deg[:T], sw_disp, sample_w)
# # # # # # # #         L_ep              = l_endpoint_72h(pred_deg[:T], gt_deg[:T], sample_w)

# # # # # # # #         L_speed = pred_deg.new_zeros(())
# # # # # # # #         if speed_pred is not None:
# # # # # # # #             L_speed = l_speed_aux(speed_pred, pred_deg[:T], gt_deg[:T], sw_pos)

# # # # # # # #         L_scorer = pred_deg.new_zeros(())
# # # # # # # #         if candidates is not None and obs_norm is not None and len(candidates) >= 2:
# # # # # # # #             L_scorer = self.scorer.auxiliary_loss(candidates, obs_norm, gt_deg[:T])

# # # # # # # #         anchor = self.loss_weights.anchor_loss()
# # # # # # # #         step_p = self.step_weights.penalty()

# # # # # # # #         total = (w_fm    * L_fm
# # # # # # # #                  + w_pos_e * L_pos_e
# # # # # # # #                  + w_pos_l * L_pos_l
# # # # # # # #                  + w_disp  * L_disp
# # # # # # # #                  + w_ep    * L_ep
# # # # # # # #                  + 0.15    * L_speed
# # # # # # # #                  + 0.03    * L_scorer
# # # # # # # #                  + anchor  + step_p)

# # # # # # # #         if not torch.isfinite(total):
# # # # # # # #             total = pred_deg.new_zeros(())

# # # # # # # #         sw_s = self.step_weights.stats()
# # # # # # # #         lw_s = self.loss_weights.stats()

# # # # # # # #         def _f(x): return x.item() if torch.is_tensor(x) else float(x)

# # # # # # # #         bd = {
# # # # # # # #             "total":   total,
# # # # # # # #             "l_fm":    _f(L_fm),
# # # # # # # #             "l_pos_e": _f(L_pos_e),
# # # # # # # #             "l_pos_l": _f(L_pos_l),
# # # # # # # #             "l_disp":  _f(L_disp),
# # # # # # # #             "l_ep":    _f(L_ep),
# # # # # # # #             "l_speed": _f(L_speed),
# # # # # # # #             "diff_w_mean": sample_w.mean().item(),
# # # # # # # #             **{f"sw_{k}": v for k, v in sw_s.items()},
# # # # # # # #             **{f"lw_{k}": v for k, v in lw_s.items()},
# # # # # # # #         }
