# # # # # # # #         bd["sw_sw_72h"]    = sw_s["sw_pos_72h"]
# # # # # # # #         bd["sw_sw_ratio"]  = sw_s["sw_pos_ratio"]
# # # # # # # #         bd["lw_lw_pos_fm"] = lw_s["lw_pos_l"] / max(lw_s["lw_fm"], 1e-6)
# # # # # # # #         return total, bd

# # # # # # # #     @torch.no_grad()
# # # # # # # #     def stats(self) -> dict:
