# # # # # # # TCDiffusion = TCFlowMatching

# # # # # # """
# # # # # # flow_matching_model_v75.py — FM v75 (Physics-Grounded Loss)
# # # # # # =============================================================
# # # # # # BUILD ON v74-fix. Thay L_disp bằng 3 physics-motivated loss terms để
# # # # # # giảm ATE gap (−20km) và CTE gap (−12km) còn lại sau v74.

# # # # # # ROOT CAUSE ANALYSIS (từ v74 training log ep0-45):
# # # # # #   ATE=162 vs target 142: L_disp penalize magnitude ratio, gradient direction
# # # # # #     không phân biệt along-track vs cross-track error → không target ATE.
# # # # # #   CTE=54 vs target 42:   Không có loss nào penalize heading deviation.
# # # # # #     cfg_guidance=1.5 cứng, không adaptive → cross-track spread lớn.
# # # # # #   Oscillation ±5km:      n_ensemble=50 → sampling variance che signal.
# # # # # #                           EMA decay=0.995 lag → EMA kém raw model.

# # # # # # v75 FIXES (3 physics loss thay L_disp):
# # # # # #   FIX-1: L_kinematic = MSE(velocity_vector_km) / norm²
# # # # # #          → ||v_err||² = ATE_component² + CTE_component²  (identity toán học)
# # # # # #          → Gradient push velocity vector đúng hướng cho cả ATE lẫn CTE
# # # # # #          → Thay hoàn toàn L_disp

# # # # # #   FIX-2: L_logspeed = MSE(log1p(speed_pred), log1p(speed_gt))   [auxiliary w=0.15]
# # # # # #          → Log scale: sai lệch 10% ở speed=10 quan trọng ngang speed=100
# # # # # #          → Bổ sung cho L_kinematic với explicit speed supervision
# # # # # #          → Đặc biệt quan trọng cho very fast storms (>80 km/6h)

# # # # # #   FIX-3: L_smooth = sin²(Δheading/2) alignment + acceleration      [auxiliary w=0.20]
# # # # # #          → Constraint từ vortex inertia: bão không đổi hướng 90°/6h
# # # # # #          → Giảm zig-zag trajectory → CTE thấp hơn
# # # # # #          → sin²(5°/2) ≈ 0.002 → recurvature (5-15°/6h) không bị penalize

# # # # # # LOSS FORMULA v75:
# # # # # #   Total = w_fm   * L_fm                    — flow matching velocity [model-learned]
# # # # # #         + w_pos  * L_pos(step_weights)     — position quality ADE proxy [model-learned]
# # # # # #         + w_kin  * L_kinematic             — velocity MSE = ATE²+CTE² [model-learned, thay L_disp]
# # # # # #         + 0.15   * L_logspeed             — log-speed auxiliary [fixed]
# # # # # #         + 0.20   * L_smooth               — heading continuity [fixed]
# # # # # #         + 0.3    * L_speed_head           — auxiliary speed prediction [fixed]
# # # # # #         + 0.05   * L_scorer              — ensemble scorer BCE [fixed]
# # # # # #         + L_anchor(loss_weights)          — weight regularization [fixed]

# # # # # # INFERENCE v75 changes:
# # # # # #   n_ensemble: 50 → 100  (giảm sampling variance ±5km → ±2.5km)
# # # # # #   ema_decay:  0.995 → 0.999  (EMA đang lag, smooth hơn ở late training)
# # # # # #   cfg_guidance: 1.5 → 2.0  (giảm cross-track spread → CTE)

# # # # # # GIỮ NGUYÊN từ v74:
# # # # # #   - VelocityField architecture (toàn bộ)
# # # # # #   - FIX-A: x0=N(0,sigma) pure noise
# # # # # #   - FIX-B: L_pos direct position loss
# # # # # #   - EMA, OT matching, CFG, LearnedStepWeights
# # # # # #   - DifficultyWeighter, EnsembleScorer
# # # # # #   - K=3 mode clustering, TTA, persistence blend
# # # # # # """
# # # # # # from __future__ import annotations

# # # # # # import csv, math, os
# # # # # # from datetime import datetime
# # # # # # from typing import Optional, Tuple

# # # # # # import torch
