# # # # #         # L_kinematic: auto-calibrated velocity vector MSE = ATE²+CTE²
# # # # #         # norm = mean gt_speed (detached), so loss is dimensionless and epoch-agnostic
# # # # #         L_kin  = l_kinematic(pred_deg[:T], gt_deg[:T], sw)

# # # # #         # L_logspeed: log-scale speed (rescues slow-storm speed accuracy)
# # # # #         L_lspd = l_logspeed(pred_deg[:T], gt_deg[:T], sw)

# # # # #         # L_smooth: heading continuity with stationary-storm masking
# # # # #         L_sm = l_smooth(pred_deg[:T], gt_deg[:T], sw)

# # # # #         total = (w_fm * L_fm
# # # # #                  + w_pos * L_pos
# # # # #                  + w_kin * L_kin
# # # # #                  + self.W_LOGSPEED * L_lspd
# # # # #                  + self.W_SMOOTH   * L_sm
# # # # #                  + lw_anc)

# # # # #         if not torch.isfinite(total):
