# # # # #         sw_s = self.step_weights.stats()   # keys: sw_ratio, sw_72h, sw_6h, ...
# # # # #         lw_s = self.loss_weights.stats()   # keys: lw_fm, lw_pos, lw_kin, lw_pos_fm
# # # # #         bd = {
# # # # #             "l_fm":        L_fm.item(),
# # # # #             "l_pos":       L_pos.item(),
# # # # #             "l_kin":       L_kin.item(),
# # # # #             "l_lspd":      L_lspd.item(),
# # # # #             "l_sm":        L_sm.item(),
# # # # #             "diff_w_mean": sample_w.mean().item(),
# # # # #             # FIX: stats() already returns keys WITH prefix (sw_72h, lw_pos_fm).
# # # # #             # Unpack directly — do NOT add f"sw_{k}" prefix again.
# # # # #             **sw_s,
# # # # #             **lw_s,
# # # # #         }
# # # # #         return total, bd

# # # # #     def forward(self, pred_deg, gt_deg, fm_vel_pred, fm_vel_target,
# # # # #                 speed_pred=None, candidates=None, obs_norm=None, epoch=0):
# # # # #         total, bd = self.compute_main_losses(
# # # # #             pred_deg, gt_deg, fm_vel_pred, fm_vel_target, epoch=epoch)

# # # # #         # Speed head auxiliary (small weight)
# # # # #         l_sh = pred_deg.new_zeros(())
