# # # #     def auxiliary_loss(self, candidates, obs_norm, gt_deg,
# # # #                         soft_temp_km=50.0):
# # # #         """
# # # #         Improved scorer training loss — v75 upgrade.

# # # #         Thay BCE binary (best=1, rest=0) bằng soft ADE labels:
# # # #             label_i = softmax(−ADE_i / soft_temp_km)

# # # #         Lý do: với binary label, scorer chỉ học phân biệt «best of N»,
# # # #         không phân biệt được «ADE=10km» vs «ADE=50km» — cả hai đều label=0.
# # # #         Với soft label, scorer học gradient liên tục:
# # # #             ADE=10km → label≈0.61,  ADE=50km → label≈0.27,  ADE=100km → label≈0.10
# # # #         → scorer học absolute quality thay vì chỉ relative ranking.

# # # #         Vẫn dùng cross-entropy (KL divergence giữa score distribution và label distribution).
# # # #         """
# # # #         if len(candidates) < 2:
# # # #             return candidates[0].new_zeros(())

# # # #         gt_b = gt_deg.permute(1, 0, 2)      # [B, T, 2]
# # # #         ades = []
# # # #         for c in candidates:
# # # #             cb = norm_to_deg(c).permute(1, 0, 2)   # [B, T, 2]
# # # #             ades.append(haversine_km(cb, gt_b).mean(1))  # [B]
# # # #         ades_t = torch.stack(ades, 0)        # [N_cand, B]

# # # #         # Soft labels: softmax(-ADE / T) over candidates dim
# # # #         soft_labels = F.softmax(-ades_t / soft_temp_km, dim=0)  # [N_cand, B]

# # # #         # Score logits for each candidate
# # # #         logits = torch.stack(
# # # #             [self.logits(c, obs_norm) for c in candidates], 0)  # [N_cand, B]

# # # #         # Cross-entropy: Σ_i soft_label_i × log_softmax(logit_i)
# # # #         log_probs = F.log_softmax(logits, dim=0)                # [N_cand, B]
# # # #         loss = -(soft_labels * log_probs).sum(0).mean()          # scalar

# # # #         return loss


