# # # # class FMv75Loss(nn.Module):
# # # #     """
# # # #     v75 loss: 3 general terms + 2 physics auxiliary + speed head + scorer.

# # # #     Total = w_fm  * L_fm                    [model-learned, init=1.0]
# # # #           + w_pos * L_pos(step_weights)     [model-learned, init=2.0]
# # # #           + w_kin * L_kinematic             [model-learned, init=1.0, replaces L_disp]
# # # #           + 0.15  * L_logspeed             [fixed auxiliary]
# # # #           + 0.20  * L_smooth               [fixed auxiliary]
# # # #           + 0.30  * L_speed_head           [fixed auxiliary]
# # # #           + 0.05  * L_scorer               [fixed auxiliary]
# # # #           + L_anchor(loss_weights)          [weight regularization]

# # # #     L_fm:        velocity MSE (flow matching objective)
# # # #     L_pos:       haversine position loss (ADE proxy, DIRECT gradient)
# # # #     L_kinematic: velocity vector MSE = ATE²+CTE² (REPLACES L_disp)
# # # #     L_logspeed:  log-speed supervision (scale-invariant speed quality)
# # # #     L_smooth:    heading continuity (vortex inertia constraint)

# # # #     DifficultyWeighter: per-sample weights ∈ [1,2]
# # # #       → continuous soft split (not binary easy/hard)
# # # #       → hard storms (high curvature, speed CV) get more gradient

# # # #     LearnedStepWeights: per-step weights (monotone, w_72h ≥ 3x w_6h)
# # # #       → both L_pos and L_kinematic use these step weights
# # # #       → aligns loss emphasis with evaluation score formula
# # # #     """
# # # #     # Fixed weights for auxiliary terms (not learned)
# # # #     W_LOGSPEED = 0.15
# # # #     W_SMOOTH   = 0.20

# # # #     def __init__(self, pred_len=12):
# # # #         super().__init__()
# # # #         self.pred_len      = pred_len
# # # #         self.step_weights  = LearnedStepWeights(n_steps=pred_len)
# # # #         self.loss_weights  = ConstrainedLossWeights(
# # # #             init_fm=1.0, init_pos=2.0, init_kin=1.0, anchor_w=0.02)
# # # #         self.diff_weighter = DifficultyWeighter()
# # # #         self.scorer        = EnsembleScorer()
# # # #         self.speed_head_aux = None   # set externally if needed

# # # #     def compute_main_losses(self, pred_deg, gt_deg,
# # # #                              fm_vel_pred, fm_vel_target,
# # # #                              epoch=0):
# # # #         T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # #         sample_w = self.diff_weighter(gt_deg[:T])  # [B] ∈ [1,2]
# # # #         sw = self.step_weights.get(n=T)             # [T] monotone learned

# # # #         w_fm  = self.loss_weights.w_fm()
# # # #         w_pos = self.loss_weights.w_pos()
# # # #         w_kin = self.loss_weights.w_kin()
# # # #         lw_anc = self.loss_weights.anchor_loss()

# # # #         # L_fm: flow matching velocity MSE
# # # #         L_fm = F.mse_loss(fm_vel_pred, fm_vel_target)

# # # #         # L_pos: direct position loss (ADE proxy, monotone gradient)
# # # #         L_pos = l_position(pred_deg[:T], gt_deg[:T], sw, d=300., sample_w=sample_w)

# # # #         # L_kinematic: auto-calibrated velocity vector MSE = ATE²+CTE²
# # # #         # norm = mean gt_speed (detached), so loss is dimensionless and epoch-agnostic
# # # #         L_kin  = l_kinematic(pred_deg[:T], gt_deg[:T], sw)

# # # #         # L_logspeed: log-scale speed (rescues slow-storm speed accuracy)
# # # #         L_lspd = l_logspeed(pred_deg[:T], gt_deg[:T], sw)

# # # #         # L_smooth: heading continuity with stationary-storm masking
# # # #         L_sm = l_smooth(pred_deg[:T], gt_deg[:T], sw)

# # # #         total = (w_fm * L_fm
# # # #                  + w_pos * L_pos
