# # # #         if spread_km < unimodal_spread_km:
# # # #             # ── UNIMODAL path: top-30% weighted mean ───────────────────
# # # #             # Math justification: E[mean of top-k] < E[top-1] always,
# # # #             # and approaches E[full mean] as k → N.
# # # #             # top-30% = 30 bản → variance ≈ 1/30 of single sample variance.
