# # # #             results.append(result)
# # # #             continue

# # # #         # ── MULTIMODAL path: K=3 with multi-checkpoint ─────────────────

# # # #         # A2 FIX: Init từ top-20% median thay vì single argmax
# # # #         # → kháng outlier (outlier với score cao không còn là seed duy nhất)
# # # #         k_seed = max(2, int(N * 0.20))
