# # # # TCDiffusion = TCFlowMatching

# # # """
# # # flow_matching_model_v76.py  ―  TC-FlowMatching v76
# # # ══════════════════════════════════════════════════════════════════════════════
# # # Architecture: GIỐNG HỆT v74 (VelocityField không đổi gì).
# # # Thay đổi DUY NHẤT: loss function + các module phụ trợ.

# # # 8 BUGS ĐÃ FIX (phân tích từ log v74 ep0-45 + TC_FlowMatching_v75_Analysis.md):

# # #   BUG-1  l_position() — sample_w.mean() scalar multiply SAU mean() →
# # #          DifficultyWeighter hoàn toàn vô hiệu (tất cả samples cùng gradient).
# # #          Verified: wrong method cho hard/easy gradient ratio = 1.000 (không phân biệt).
# # #          Fix: (huber * sw_step[:,None] * sample_w[None,:]).mean() / d
# # #               → hard sample (sw=1.8) nhận 1.8× gradient của easy sample.

# # #   BUG-2  l_displacement() — ratio = err/gt_spd không clamp →
# # #          slow storm (15 km/h) err=100km: ratio=6.7, huber=6.42
# # #          fast storm (100 km/h) err=100km: ratio=1.0, huber=0.75
# # #          → 8.6× imbalance. Slow storms dominate gradient, training lệch.
# # #          Fix: clamp(ratio, max=5.0), delta=1.0, chia /2 normalize scale.

# # #   BUG-3  LearnedStepWeights — zeros+0.5 init → ratio khởi đầu 12× →
# # #          decay về 4.8× sau 45 epoch (log v74: ep0=12.0, ep45=4.8).
# # #          Khi ratio<5: 72h nhận gradient yếu → plateau.
# # #          Fix: linspace(-0.3, 1.5) init → ratio khởi đầu 23× (nhiều buffer hơn).
# # #               penalty = 0.05 × relu(8 - ratio)² → duy trì ratio ≥ 8.

# # #   BUG-4  ConstrainedLossWeights — 3 weights share gradient path từ total_loss.
# # #          Khi L_disp noisy (BUG-2): gradient nhiễu lan vào w_pos → w_pos học sai.
# # #          Không có explicit long-range signal từ ep0.
# # #          Fix: tách L_pos thành L_pos_early (step 0..T//2-1) và
# # #               L_pos_late (step T//2..T-1), weights riêng biệt.
# # #               w_pos_late init=3.0 > w_pos_early=1.5 → long-range focus từ ep0.
# # #               Gradient paths độc lập → L_disp noise không nhiễu vào w_pos_late.

# # #   BUG-5  Val loss dùng augmented data → val_loss oscillate →
# # #          scheduler LR decay sai thời điểm.
# # #          Fix: epoch=-1 → skip augmentation trong get_loss_breakdown().
# # #               Val loop dùng epoch=-1.

# # #   BUG-6  Saver.cnt reset CHỈ khi composite score improve →
# # #          early stop sai khi model đang học individual metrics.
# # #          Fix: reset cnt khi ANY metric (ADE/72h/ATE/CTE) improve.

# # #   BUG-7  sched.step() có điều kiện (khi scaler không giảm) →
# # #          ~5% NaN batches × 257 steps × 45 epochs = 578 steps bị skip →
# # #          LR lệch đáng kể so với schedule.
# # #          Fix: sched.step() unconditional trong try/except.

# # #   BUG-8  grad_clip áp dụng cho step_weights (12 params) và loss_weights (4 params) →
# # #          chúng học chậm, không adapt kịp.
# # #          Fix: chỉ clip backbone params. Learned weights: KHÔNG clip.

# # # LOSS FORMULA v76 — TẤT CẢ WEIGHTS TỰ HỌC:

# # #   Total = w_fm    × L_fm                          (flow matching objective)
# # #         + w_pos_e × L_pos_early(step 0..T//2-1)   (short-range, ADE proxy)
# # #         + w_pos_l × L_pos_late (step T//2..T-1)   (long-range, 72h focus)
# # #         + w_disp  × L_disp_normalized             (velocity stability)
# # #         + sw.penalty()                            (maintain sw_ratio ≥ 8×)
# # #         + lw.anchor_loss()                        (prevent weight collapse)

# # #   4 learned weights: w_fm ∈ [0.3,4], w_pos_e ∈ [0.5,5], w_pos_l ∈ [1,8], w_disp ∈ [0.1,3]
# # #   Tất cả qua softplus → dương + clamp → bounded.
# # #   anchor_loss (L2 từ init) ngăn weights collapse về 0.
# # #   DifficultyWeighter: sample_w per-sample [B], broadcast [1,B] trước mean() — BUG-1 fix.
# # # """
# # # from __future__ import annotations

# # # import csv, math, os
# # # from datetime import datetime
# # # from typing import Optional

# # # import torch
# # # import torch.nn as nn
# # # import torch.nn.functional as F

# # # from Model.FNO3D_encoder                import FNO3DEncoder
