# # # class DifficultyWeighter(nn.Module):
# # #     """
# # #     Per-sample difficulty weight ∈ [1, 2]. Fully learned.
# # #     Init: bias=-2.0 → sigmoid(-2.0)≈0.12 → weight≈1.12 (near-uniform at ep0).
# # #     """
# # #     def __init__(self):
# # #         super().__init__()
# # #         self.fc = nn.Linear(3, 1, bias=True)
# # #         nn.init.zeros_(self.fc.weight)
# # #         nn.init.constant_(self.fc.bias, -2.0)

# # #     def _features(self, gt_deg: torch.Tensor) -> torch.Tensor:
# # #         """(T,B,2) degrees → (B,3) difficulty features [curvature, speed_cv, excess_curv]."""
# # #         B = gt_deg.shape[1]
# # #         v = velocity_km_s(gt_deg)                              # (T-1,B,2)
# # #         if v.shape[0] >= 2:
# # #             h  = torch.atan2(v[..., 0], v[..., 1])            # (T-1,B) heading
# # #             dh = h[1:] - h[:-1]
# # #             dh = (dh + math.pi) % (2 * math.pi) - math.pi    # wrap [-π,π]
# # #             curv_rate   = dh.abs().mean(0)                     # (B,)
# # #             excess_curv = F.relu(dh.abs() - math.pi / 4).mean(0)
# # #         else:
# # #             curv_rate = excess_curv = gt_deg.new_zeros(B)
# # #         spd      = v.norm(dim=-1)                              # (T-1,B)
# # #         mean_spd = spd.mean(0).clamp(min=1.)
# # #         speed_cv = (spd.std(0) / mean_spd).clamp(max=3.)
# # #         d1 = (curv_rate   / (math.pi / 2)).clamp(0., 1.)
# # #         d2 = speed_cv.clamp(0., 1.)
# # #         d3 = (excess_curv / (math.pi / 4)).clamp(0., 1.)
# # #         return torch.stack([d1, d2, d3], dim=-1)               # (B,3)

# # #     def forward(self, gt_deg: torch.Tensor) -> torch.Tensor:
# # #         """Returns (B,) weights ∈ [1, 2]."""
# # #         return 1.0 + torch.sigmoid(self.fc(self._features(gt_deg)).squeeze(-1))


