# # # #  Loss functions  [BUG-1, BUG-2 FIX]
# # # # ─────────────────────────────────────────────────────────────────────────────

# # # def l_position(pred_deg:   torch.Tensor,
# # #                gt_deg:     torch.Tensor,
# # #                sw:         torch.Tensor,
# # #                sample_w:   torch.Tensor,
# # #                step_range: tuple,
# # #                d:          float = 300.) -> torch.Tensor:
# # #     """
# # #     Direct haversine position loss on a slice of steps.

# # #     BUG-1 FIX — sample_w broadcast per-sample [T,B], NOT mean() scalar.

# # #     SAIS (v74):
# # #         loss = (huber * sw[:,None]).mean() / d     # scalar
# # #         loss = loss * sample_w.mean()              # × scalar 1.12
# # #         → tất cả samples cùng gradient, DifficultyWeighter vô hiệu

# # #     ĐÚNG:
# # #         loss = (huber * sw[:,None] * sample_w[None,:]).mean() / d
# # #         → sample b nhận gradient × sample_w[b]
# # #         → hard storm (sw=1.8) nhận 1.8× gradient của easy storm (sw=1.0)
# # #         → Verified: ratio = 1.0 (wrong) vs 1.8 (correct) với uniform huber test

# # #     step_range: (start, end) half-open interval on T axis.
# # #     d=300 km: Huber threshold — linear gradient when error > 300 km.
# # #     """
# # #     s, e = step_range
# # #     T    = min(pred_deg.shape[0], gt_deg.shape[0])
# # #     e    = min(e, T)
# # #     if s >= e:
# # #         return pred_deg.new_zeros(())

# # #     dist = haversine_km(pred_deg[s:e], gt_deg[s:e])           # (n_steps, B)
# # #     hub  = torch.where(dist < d,
# # #                         dist.pow(2) / (2. * d),
# # #                         dist - d / 2.)                         # (n_steps, B)

# # #     sw_s = sw[s:e]                                             # (n_steps,)

# # #     # BUG-1 FIX: sample_w[None,:] broadcasts to [1,B] → each sample b gets
# # #     # gradient scaled by sample_w[b], not by the batch average
# # #     return (hub * sw_s.unsqueeze(1) * sample_w.unsqueeze(0)).mean() / d


# # # def l_displacement(pred_deg: torch.Tensor,
# # #                    gt_deg:   torch.Tensor,
# # #                    sw:       torch.Tensor,
# # #                    sample_w: torch.Tensor) -> torch.Tensor:
# # #     """
# # #     Velocity displacement stability loss.

# # #     BUG-2 FIX — clamp ratio + normalize scale.

# # #     SAIS (v74):
# # #         ratio = err_km / gt_spd          # no clamp, delta=0.5
# # #         → slow storm (15 km/h) ratio=6.7, huber=6.42
# # #         → fast storm (100 km/h) ratio=1.0, huber=0.75
# # #         → 8.6× imbalance, slow storms dominate gradient

# # #     ĐÚNG:
# # #         ratio = (err_km / gt_spd).clamp(max=5.)   # capped
# # #         huber with delta=1.0, divided by /2.0
# # #         → max ratio=5, max huber=4.5 regardless of storm speed
# # #         → gradient balanced across slow and fast storms

# # #     BUG-1 FIX cũng được apply: sample_w broadcast per-sample.
# # #     """
# # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # #     if T < 3:
# # #         return pred_deg.new_zeros(())

# # #     v_pred = velocity_km_s(pred_deg[:T])                      # (T-1, B, 2)
# # #     v_gt   = velocity_km_s(gt_deg[:T])                        # (T-1, B, 2)
# # #     err    = (v_pred - v_gt).norm(dim=-1)                     # (T-1, B) km/6h
# # #     spd    = v_gt.norm(dim=-1).clamp(min=5.)                  # (T-1, B), floor 5 km/h

# # #     # BUG-2 FIX: clamp ratio max=5.0 → balanced across storm speeds
# # #     ratio = (err / spd).clamp(max=5.)                         # (T-1, B) dimensionless

# # #     hub = F.huber_loss(ratio, torch.zeros_like(ratio),
# # #                         delta=1.0, reduction='none')           # (T-1, B)

# # #     sw_s = sw[:T - 1]                                         # (T-1,)

# # #     # BUG-1 FIX applied here too: per-sample weighting
# # #     return (hub * sw_s.unsqueeze(1) * sample_w.unsqueeze(0)).mean() / 2.


