# # # class FMv76Criterion(nn.Module):
# # #     """
# # #     v76 master loss. TẤT CẢ 4 weights tự học.

# # #     Total = w_fm    × L_fm
# # #           + w_pos_e × L_pos_early(step 0..T//2-1)
# # #           + w_pos_l × L_pos_late (step T//2..T-1)
# # #           + w_disp  × L_disp
# # #           + sw.penalty()       ← keep sw_ratio ≥ 8×  (BUG-3 fix)
# # #           + lw.anchor_loss()   ← prevent weight collapse

# # #     Key properties:
# # #     - L_pos_early và L_pos_late có gradient paths riêng (BUG-4 fix)
# # #     - Tất cả losses dùng sample_w broadcast per-sample (BUG-1 fix)
# # #     - L_disp dùng clamped ratio (BUG-2 fix)
# # #     - DifficultyWeighter fully learned, range [1,2]
# # #     """
# # #     def __init__(self, pred_len: int = 12):
# # #         super().__init__()
# # #         self.pred_len      = pred_len
# # #         self.step_weights  = LearnedStepWeights(n_steps=pred_len, min_ratio=8.0)
# # #         self.loss_weights  = ConstrainedLossWeights(
# # #             init_fm=1.0, init_pos_e=1.5, init_pos_l=3.0,
# # #             init_disp=0.8, anchor_w=0.01)
# # #         self.diff_weighter = DifficultyWeighter()

# # #     def compute(self,
# # #                 pred_deg:      torch.Tensor,
# # #                 gt_deg:        torch.Tensor,
# # #                 fm_vel_pred:   torch.Tensor,
# # #                 fm_vel_target: torch.Tensor
# # #                 ) -> tuple[torch.Tensor, dict]:
# # #         """
# # #         Args:
# # #             pred_deg:      (T, B, 2) degrees — predicted trajectory
# # #             gt_deg:        (T, B, 2) degrees — ground-truth trajectory
# # #             fm_vel_pred:   flow matching velocity prediction (B, T, 4)
# # #             fm_vel_target: flow matching velocity target     (B, T, 4)
# # #         Returns:
# # #             total: scalar loss
# # #             bd:    dict with per-loss values for logging
# # #         """
# # #         T  = min(pred_deg.shape[0], gt_deg.shape[0])
# # #         sw = self.step_weights.get(n=T)          # (T,) monotone, mean=1

# # #         # Per-sample difficulty weights: (B,) ∈ [1, 2]
# # #         # NOTE: passed INTO each loss function, NOT .mean() here
# # #         smp = self.diff_weighter(gt_deg[:T])     # (B,)

# # #         # Learned weights
# # #         w_fm  = self.loss_weights.w_fm()
# # #         w_pe  = self.loss_weights.w_pos_e()
# # #         w_pl  = self.loss_weights.w_pos_l()
# # #         w_dsp = self.loss_weights.w_disp()

# # #         mid = T // 2   # boundary early/late: step 0..mid-1 | mid..T-1

# # #         # ── L_fm ─────────────────────────────────────────────────────────────
# # #         L_fm = F.mse_loss(fm_vel_pred, fm_vel_target)

# # #         # ── L_pos_early  (step 0..mid-1 = 6h..36h range) ────────────────────
# # #         # BUG-1 fix applied inside l_position()
# # #         L_pe = l_position(pred_deg[:T], gt_deg[:T], sw, smp,
# # #                            step_range=(0, mid), d=300.)

# # #         # ── L_pos_late   (step mid..T-1 = 48h..72h range) ───────────────────
# # #         # BUG-4 fix: gradient path INDEPENDENT of L_pe and L_disp
# # #         L_pl = l_position(pred_deg[:T], gt_deg[:T], sw, smp,
# # #                            step_range=(mid, T), d=300.)

# # #         # ── L_disp ───────────────────────────────────────────────────────────
# # #         # BUG-2 fix: clamped ratio + normalized scale
# # #         # BUG-1 fix: per-sample weighting
# # #         L_dsp = l_displacement(pred_deg[:T], gt_deg[:T], sw, smp)

# # #         # ── Regularizers ─────────────────────────────────────────────────────
# # #         sw_pen  = self.step_weights.penalty()     # BUG-3 fix: maintain ratio ≥ 8×
# # #         lw_anc  = self.loss_weights.anchor_loss() # prevent weight collapse

# # #         # ── Total ─────────────────────────────────────────────────────────────
# # #         total = (w_fm  * L_fm
# # #                  + w_pe  * L_pe
# # #                  + w_pl  * L_pl
# # #                  + w_dsp * L_dsp
# # #                  + sw_pen
# # #                  + lw_anc)

# # #         if not torch.isfinite(total):
# # #             total = pred_deg.new_zeros(())

# # #         bd: dict = {
# # #             "l_fm":        L_fm.item(),
# # #             "l_pos_e":     L_pe.item(),
# # #             "l_pos_l":     L_pl.item(),
# # #             "l_disp":      L_dsp.item(),
# # #             "sw_pen":      sw_pen.item(),
# # #             "lw_anc":      lw_anc.item(),
# # #             "diff_w_mean": smp.mean().item(),
# # #             **self.step_weights.stats(),   # sw_ratio, sw_72h, ...
# # #             **self.loss_weights.stats(),   # lw_fm, lw_pos_e, lw_pos_l, ...
# # #         }
# # #         return total, bd

# # #     def forward(self, *a, **kw):
# # #         return self.compute(*a, **kw)


